// Single source of truth for the Accounts screen copy + the error-surface
// messages (FR-ACCT-01/03/04/05, NFR-I18N-01). Shared by the page, the server
// actions, and the accounts eval case so the graded copy is exactly what the user
// sees. Pure module (only a type import) — importing it pulls no UI tree.

import type { AccountErrorCode } from "@/src/domain/account";

export const ACCOUNTS_PAGE = {
  title: "Рахунки",
  description:
    "Керуйте рахунками та оберіть типовий. Усі рахунки ведуться у гривні (UAH).",
  createHeading: "Новий рахунок",
  nameLabel: "Назва рахунку",
  namePlaceholder: "Напр. Картка, Готівка, Заощадження",
  createLabel: "Додати рахунок",
  defaultBadge: "Типовий",
  setDefaultLabel: "Зробити типовим",
  renameLabel: "Нова назва",
  renameSubmitLabel: "Перейменувати",
  archiveLabel: "Архівувати",
  emptyTitle: "Ще немає рахунків",
  emptyDescription:
    "Типовий рахунок «Готівка» створюється автоматично, щоб операції було куди записувати.",
  balanceHint: "Баланс кожного рахунку зʼявиться разом із журналом операцій.",
} as const;

/** Canonical Ukrainian copy for each account error code, shown in the banner. */
export const ACCOUNT_ERRORS: Record<AccountErrorCode, string> = {
  "name-required": "Вкажіть назву рахунку — поле не може бути порожнім.",
  "name-too-long": "Назва рахунку задовга. Будь ласка, скоротіть її.",
  "not-found": "Рахунок не знайдено — можливо, його вже архівовано.",
  "cannot-archive-default":
    "Не можна архівувати типовий рахунок. Спершу зробіть типовим інший рахунок.",
  "cannot-archive-last":
    "Не можна архівувати останній активний рахунок — має лишатися щонайменше один.",
};

/** Maps a `?formError=` code to its banner message; null when there is no error. */
export function accountErrorMessage(code: string | undefined): string | null {
  if (!code) return null;
  return (
    ACCOUNT_ERRORS[code as AccountErrorCode] ??
    "Не вдалося виконати дію. Спробуйте ще раз."
  );
}

// Accounts output eval case for Finup.
//
// Unit tests prove the archive-guard *logic*; this case grades the user-visible
// *quality* of the accounts copy — whether the screen labels the default account
// unambiguously and whether the archive-rejection messages explain WHY an action
// was blocked (and what to do instead) in calm, Ukrainian-first language, rather
// than a generic "something went wrong".
//
// `produce()` reads the REAL copy module (accounts-content.ts) — the single
// source of truth shared with the page — so the judge grades the live product.

export type EvalCase = {
  id: string;
  trace: string[];
  dimension: string;
  capability: string;
  scenario: string;
  produce: () => Promise<string>;
  rubric: string[];
};

export const cases: EvalCase[] = [
  {
    id: "eval-accounts-error-clarity",
    trace: ["FR-ACCT-05", "FR-ACCT-01", "NFR-I18N-01"],
    dimension: "ua-error-clarity",
    capability: "accounts",
    scenario:
      "A user manages accounts and attempts to archive the default or the last remaining account.",
    produce: async () => {
      const { ACCOUNTS_PAGE, ACCOUNT_ERRORS } = await import(
        "@/src/modules/accounts/ui/accounts-content"
      );
      return [
        "Route: /accounts",
        `Heading: ${ACCOUNTS_PAGE.title}`,
        `Intro: ${ACCOUNTS_PAGE.description}`,
        `Default label: ${ACCOUNTS_PAGE.defaultBadge}`,
        `Set-default action: ${ACCOUNTS_PAGE.setDefaultLabel}`,
        `Archive action: ${ACCOUNTS_PAGE.archiveLabel}`,
        ...Object.entries(ACCOUNT_ERRORS).map(
          ([code, message]) => `Error[${code}]: ${message}`,
        ),
      ].join("\n");
    },
    rubric: [
      "CRITICAL: every string is Ukrainian-first with no English product jargon",
      "CRITICAL: the archive-rejection messages explain WHY the action is blocked (default account / last active account) and imply what the user can do instead",
      "CRITICAL: the default account is labelled clearly and unambiguously",
      "the tone is calm and finance-oriented, not alarming",
      "messages are specific to the situation, never a generic 'something went wrong'",
    ],
  },
];

// @trace FR-ACCT-05, FR-ACCT-01, NFR-I18N-01
